import hashlib, json, os

CACHE_PATH = "summary_cache.json"

def load_cache() -> dict[str, str]:
    if os.path.exists(CACHE_PATH):
        with open(CACHE_PATH) as f:
            return json.load(f)
    return {}

def save_cache(cache: dict[str, str]) -> None:
    with open(CACHE_PATH, "w") as f:
        json.dump(cache, f, indent=2)

def chunk_hash(text: str) -> str:
    return hashlib.sha256(text.encode()).hexdigest()

async def summarise_with_cache(
    chunks: list,
    summarise_chain,
) -> list[str]:
    cache = load_cache()
    results = []
    changed = False

    for chunk in chunks:
        h = chunk_hash(chunk.page_content)
        if h in cache:
            results.append(cache[h])  # cache hit — no LLM call
        else:
            summary = await summarise_chain.ainvoke({"text": chunk.page_content})
            cache[h] = summary
            results.append(summary)
            changed = True

    if changed:
        save_cache(cache)

    return results

def recall_at_k(query, relevant_ids, retriever_fn, k=5) -> float:
    results = retriever_fn(query)[:k]
    retrieved = {str(hash(d.page_content[:200])) for d in results}
    return len(retrieved & set(relevant_ids)) / len(relevant_ids)

eval_cases = [
    {"query": "how does attention compute weights", "relevant": ["chunk_3", "chunk_7"]},
    {"query": "positional encoding mechanism",       "relevant": ["chunk_5"]},
]

for case in eval_cases:
    q, rel = case["query"], set(case["relevant"])
    flat   = recall_at_k(q, rel, lambda x: vectorstore_flat.similarity_search(x, k=5))
    summ   = recall_at_k(q, rel, lambda x: summary_dense_retriever_invoke(x, k=5))
    print(f"{q[:40]}")
    print(f"  flat embedding: {flat:.2f}  summary index: {summ:.2f}")
